"use client";

import { useFilter } from "@ark-ui/react";
import {
  Combobox as ArkCombobox,
  useListCollection,
} from "@ark-ui/react/combobox";
import { Dialog as ArkDialog } from "@ark-ui/react/dialog";
import { SearchIcon } from "lucide-react";
import React, { type ComponentProps, Fragment } from "react";
import { cn } from "@/lib/utils";
import {
  Combobox,
  ComboboxControl,
  ComboboxEmpty,
  ComboboxGroup,
  ComboboxGroupLabel,
  ComboboxItem,
  ComboboxList,
} from "@/registry/react/components/combobox";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/registry/react/components/dialog";
import {
  InputGroup,
  InputGroupAddon,
  InputGroupInput,
} from "@/registry/react/components/input-group";

export const CommandDialog = Dialog;

export function CommandDialogTrigger(
  props: React.ComponentProps<typeof DialogTrigger>
) {
  return <DialogTrigger data-slot="command-dialog-trigger" {...props} />;
}

export const CommandOverlay = (
  props: React.ComponentProps<typeof ArkDialog.Backdrop>
) => {
  const { className, ...rest } = props;

  return (
    <ArkDialog.Backdrop
      className={cn(
        "fixed inset-0 z-50 bg-black/32 backdrop-blur-sm transition-all duration-200 data-[state=closed]:opacity-0 data-[state=open]:opacity-100",
        className
      )}
      data-slot="command-dialog-backdrop"
      {...rest}
    />
  );
};

export const CommandDialogContent = (
  props: React.ComponentProps<typeof DialogContent> & {
    description?: string;
    showCloseButton?: boolean;
    title?: string;
  }
) => {
  const {
    className,
    description = "Search for a command to run...",
    showCloseButton = false,
    title = "Command Palette",
    children,
    ...rest
  } = props;

  return (
    <DialogContent
      className={cn("overflow-hidden rounded-xl p-0", className)}
      data-slot="command-dialog-popup"
      showCloseButton={showCloseButton}
      {...rest}
    >
      <DialogHeader className="sr-only">
        <DialogTitle>{title}</DialogTitle>
        <DialogDescription>{description}</DialogDescription>
      </DialogHeader>
      {children}
    </DialogContent>
  );
};

export interface CommandItemValue {
  label: string;
  shortcut?: string;
  value: string;
}

export interface CommandGroupValue {
  items: CommandItemValue[];
  value: string;
}

interface CommandContextValue {
  collection: { group: () => Iterable<[string, CommandItemValue[]]> };
  filter: ReturnType<typeof useListCollection>["filter"];
  groupedItems: CommandGroupValue[];
}

const CommandContext = React.createContext<CommandContextValue | null>(null);

interface CommandProps
  extends Omit<ComponentProps<typeof Combobox>, "collection"> {
  /**
   * Collection for advanced usage. When not provided with items, must be passed for the command to work.
   */
  collection?: ComponentProps<typeof Combobox>["collection"];
  /**
   * Grouped items for the command palette. When provided, collection and filter are created internally.
   */
  items?: CommandGroupValue[];
}

function flattenGroupedItems(
  groupedItems: CommandGroupValue[]
): (CommandItemValue & { __group: string })[] {
  return groupedItems.flatMap((group) =>
    group.items.map((item) => ({ ...item, __group: group.value }))
  );
}

export function Command({
  items: groupedItemsProp,
  collection: collectionProp,
  onInputValueChange: onInputValueChangeProp,
  className,
  ...props
}: CommandProps) {
  const { contains } = useFilter({ sensitivity: "base" });

  const flatItems = React.useMemo(
    () => (groupedItemsProp ? flattenGroupedItems(groupedItemsProp) : []),
    [groupedItemsProp]
  );

  const { collection, filter } = useListCollection({
    filter: contains,
    groupBy: (item) => item.__group,
    initialItems: flatItems,
  });

  const handleInputValueChange = React.useCallback(
    (details: { inputValue: string }) => {
      filter(details.inputValue);
      onInputValueChangeProp?.(details);
    },
    [filter, onInputValueChangeProp]
  );

  const effectiveCollection = collectionProp ?? collection;
  const effectiveOnInputValueChange = collectionProp
    ? onInputValueChangeProp
    : handleInputValueChange;

  const contextValue = React.useMemo<CommandContextValue>(
    () => ({
      collection: effectiveCollection as {
        group: () => Iterable<[string, CommandItemValue[]]>;
      },
      filter,
      groupedItems: groupedItemsProp ?? [],
    }),
    [effectiveCollection, filter, groupedItemsProp]
  );

  return (
    <CommandContext.Provider value={contextValue}>
      <Combobox
        className={cn(
          "flex size-full flex-col overflow-hidden rounded-xl bg-popover p-1 text-popover-foreground",
          className
        )}
        collection={
          effectiveCollection as ComponentProps<typeof Combobox>["collection"]
        }
        data-slot="command"
        disableLayer
        inputBehavior="autohighlight"
        onInputValueChange={effectiveOnInputValueChange}
        open
        {...props}
      />
    </CommandContext.Provider>
  );
}

export const CommandInput = (
  props: React.ComponentProps<typeof ArkCombobox.Input>
) => {
  const { className, size: _size, ...rest } = props;

  return (
    <div className="p-1 pb-0" data-slot="command-input-wrapper">
      <ComboboxControl>
        <InputGroup
          className={cn(
            "h-8 rounded-lg border-input/30 bg-input/30 shadow-none *:data-[slot=input-group-addon]:pl-2"
          )}
        >
          <ArkCombobox.Input asChild>
            <InputGroupInput
              autoFocus
              className={cn(
                "w-full text-sm outline-none disabled:cursor-not-allowed disabled:opacity-50",
                className
              )}
              data-slot="command-input"
              {...rest}
            />
          </ArkCombobox.Input>
          <InputGroupAddon>
            <SearchIcon aria-hidden className="size-4 shrink-0 opacity-50" />
          </InputGroupAddon>
        </InputGroup>
      </ComboboxControl>
    </div>
  );
};

interface CommandListProps
  extends Omit<ComponentProps<typeof ComboboxList>, "children"> {
  children: (group: CommandGroupValue, index: number) => React.ReactNode;
}

export const CommandList = (props: CommandListProps) => {
  const { className, children, ...rest } = props;

  const { collection } = useCommandContext();

  return (
    <ComboboxList
      className={cn(
        "max-h-72 scroll-py-1 overflow-y-auto overflow-x-hidden outline-none [scrollbar-width:none] [&::-webkit-scrollbar]:hidden",
        className
      )}
      data-slot="command-list"
      {...rest}
    >
      {Array.from(
        (
          collection as { group: () => Iterable<[string, CommandItemValue[]]> }
        ).group()
      ).map(([groupKey, groupItems], index) =>
        children(
          {
            items: groupItems,
            value: groupKey,
          },
          index
        )
      )}
    </ComboboxList>
  );
};

export const CommandEmpty = (
  props: React.ComponentProps<typeof ComboboxEmpty>
) => {
  const { className, children, ...rest } = props;

  return (
    <ComboboxEmpty
      className={cn("py-6 text-center text-sm", className)}
      data-slot="command-empty"
      {...rest}
    >
      {children || "No results found."}
    </ComboboxEmpty>
  );
};

export const CommandPanel = (props: React.ComponentProps<"div">) => {
  const { className, children, ...rest } = props;

  return (
    <ArkCombobox.Content
      className={cn(
        "relative -mx-px min-h-0 rounded-xl border border-b-0 bg-popover p-1 shadow-sm",
        "overflow-y-auto outline-none",
        "[:not(.has-[+[data-slot=command-footer]])]:rounded-b-2xl [:not(.has-[+[data-slot=command-footer]])]:border-b",
        className
      )}
      data-slot="command-panel"
      {...rest}
    >
      {children}
    </ArkCombobox.Content>
  );
};

export const CommandGroup = (
  props: React.ComponentProps<typeof ComboboxGroup>
) => {
  const { className, ...rest } = props;

  return (
    <ComboboxGroup
      className={cn(
        "overflow-hidden p-1 text-foreground **:data-[slot=combobox-group-label]:px-2 **:data-[slot=combobox-group-label]:py-1.5 **:data-[slot=combobox-group-label]:font-medium **:data-[slot=combobox-group-label]:text-muted-foreground **:data-[slot=combobox-group-label]:text-xs",
        className
      )}
      data-slot="command-group"
      {...rest}
    />
  );
};

export const CommandGroupLabel = (
  props: React.ComponentProps<typeof ComboboxGroupLabel>
) => {
  const { className, ...rest } = props;

  return (
    <ComboboxGroupLabel
      className={cn(
        "px-2 py-1.5 font-medium text-muted-foreground text-xs",
        className
      )}
      data-slot="command-group-label"
      {...rest}
    />
  );
};

interface CommandCollectionProps {
  children: (item: CommandItemValue) => React.ReactNode;
  items: CommandItemValue[];
}

export const CommandCollection = (props: CommandCollectionProps) => {
  const { children, items } = props;

  return (
    <>
      {items.map((item) => (
        <Fragment key={item.value}>{children(item)}</Fragment>
      ))}
    </>
  );
};

interface CommandItemProps
  extends Omit<React.ComponentProps<typeof ComboboxItem>, "item"> {
  /**
   * Item to render.
   */
  item: CommandItemValue;
}

export const CommandItem = (props: CommandItemProps) => {
  const { className, item, ...rest } = props;

  return (
    <ComboboxItem
      className={cn(
        "group/command-item relative flex cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 pe-8 text-sm outline-none",
        "data-highlighted:bg-muted data-highlighted:text-foreground data-highlighted:[&_svg]:text-foreground",
        "data-disabled:pointer-events-none data-disabled:opacity-50",
        "in-data-[slot=dialog-content]:rounded-lg",
        "**:data-[slot=combobox-item-indicator]:ml-auto **:data-[slot=combobox-item-indicator]:opacity-0 **:data-[slot=combobox-item-indicator]:shrink-0",
        "**:data-[slot=combobox-item-indicator]:group-data-[checked=true]/command-item:opacity-100 **:data-[slot=combobox-item-indicator]:group-has-data-[slot=command-shortcut]/command-item:hidden",
        "[&_svg:not([class*='size-'])]:size-4 [&_svg]:pointer-events-none [&_svg]:shrink-0",
        className
      )}
      data-slot="command-item"
      item={item}
      showIndicator
      {...rest}
    />
  );
};

export const CommandSeparator = (props: React.ComponentProps<"div">) => {
  const { className, ...rest } = props;

  return (
    <div
      className={cn("-mx-1 h-px bg-border", className)}
      data-slot="command-separator"
      {...rest}
    />
  );
};

export const CommandShortcut = (props: React.ComponentProps<"span">) => {
  const { className, ...rest } = props;

  return (
    <span
      className={cn(
        "ml-auto text-muted-foreground text-xs tracking-widest group-data-highlighted/command-item:text-foreground",
        className
      )}
      data-slot="command-shortcut"
      {...rest}
    />
  );
};

export const CommandFooter = (props: React.ComponentProps<"div">) => {
  const { className, ...rest } = props;

  return (
    <div
      className={cn(
        "flex items-center justify-between gap-2 rounded-b-[calc(var(--radius-2xl,1rem)-1px)] border-t px-5 py-3 text-muted-foreground text-xs",
        className
      )}
      data-slot="command-footer"
      {...rest}
    />
  );
};

const useCommandContext = () => {
  const context = React.useContext(CommandContext);

  if (!context) {
    throw new Error("Command components must be used within a Command");
  }
  return context;
};
